-- ═══════════════════════════════════════════════════════════════
-- Topton Media — Blog Post Data Migration
-- Inserts all 60 existing blog posts into the blog_posts table.
-- Uses ON CONFLICT (slug) DO UPDATE so it's safe to re-run.
-- ═══════════════════════════════════════════════════════════════

do $$
begin
  if not exists (select 1 from information_schema.columns where table_name='blog_posts' and column_name='related_service') then
    alter table blog_posts add column related_service text;
  end if;
  if not exists (select 1 from information_schema.columns where table_name='blog_posts' and column_name='quick_answer') then
    alter table blog_posts add column quick_answer text;
  end if;
  if not exists (select 1 from information_schema.columns where table_name='blog_posts' and column_name='updated_at') then
    alter table blog_posts add column updated_at timestamptz default now();
  end if;
end $$;

do $$
begin
  if not exists (select 1 from pg_constraint where conname = 'blog_posts_slug_unique') then
    alter table blog_posts add constraint blog_posts_slug_unique unique (slug);
  end if;
end $$;

insert into blog_posts (slug, title, meta_title, meta_description, category, related_service, excerpt, quick_answer, hero_image, read_minutes, keywords, content, faqs, published)
values ('reduce-app-install-cost-nigeria', 'How to Reduce App Install Cost in Nigeria: A Practical Guide for 2026', 'How to Reduce App Install Cost in Nigeria (2026 Guide) — Topton Media', 'Nigerian app install costs are rising fast. Learn the exact targeting, creative, and bidding strategies that keep cost per install under control in 2026.', 'User Acquisition', 'user-acquisition', 'Cost per install in Nigeria has climbed steadily over the past two years. Here is what is actually driving that, and the specific levers that bring it back down without sacrificing user quality.', 'Reduce app install cost in Nigeria by tightening audience targeting to activated-user lookalikes, refreshing ad creative 5-10 times per month, and tracking activation events rather than raw installs. Well-optimised campaigns typically run ₦800-₦2,000 CPI.', 'https://images.unsplash.com/photo-1533750349088-cd871a92f312?w=1400&q=80', 8, ARRAY['app install cost Nigeria', 'reduce CPI Nigeria', 'Nigerian app marketing', 'user acquisition Nigeria', 'mobile app advertising Lagos'], '[{"heading": "Why App Install Costs Are Rising Across Nigerian Platforms", "paragraphs": ["If you have run app install campaigns in Nigeria over the last eighteen months, you have likely watched cost per install creep upward even as your targeting and creative stayed roughly the same. This is not your imagination. More Nigerian apps are competing for the same pool of Android users on Meta, Google, and TikTok, and the auction-based pricing on these platforms means more competition translates directly into higher costs.", "There is also a currency dimension specific to Nigeria. Most ad platforms bill in USD or set minimum bids in USD-equivalent terms, so naira depreciation against the dollar has quietly inflated the effective cost of every campaign, even when nothing else has changed. Add to that the post-iOS 14.5 measurement gaps that still affect attribution accuracy industry-wide, and it becomes clear why budgets that used to deliver a certain install volume now deliver noticeably less.", "None of this means install costs are simply out of your control. It means the strategies that worked two years ago — broad targeting, generic creative, \"spray and pray\" budget allocation — no longer hold up. What works now is tighter audience definition, creative built specifically for each platform, and a willingness to kill underperforming ad sets quickly rather than waiting out a campaign."]}, {"heading": "Fix Your Targeting Before You Touch Your Budget", "paragraphs": ["The single biggest lever for reducing cost per install is not creative or bidding strategy — it is audience quality. Most Nigerian apps targeting too broadly end up paying to acquire users who were never going to activate in the first place, which inflates blended CPI even when the headline number looks acceptable.", "Lookalike audiences built from your highest-value existing users (not just any installer, but users who activated, transacted, or stayed past day 7) consistently outperform broad targeting. If you do not yet have enough seed data to build a meaningful lookalike, start with interest and behavioural targeting tightly scoped to your actual use case, and resist the temptation to widen it just to hit volume targets faster."], "bullets": ["Build lookalikes from activated users, not just any installer", "Exclude existing users from acquisition campaigns to avoid wasted spend", "Layer behavioural signals (device type, connection speed) relevant to your app category", "Test narrow audiences before widening — it is easier to scale a working segment than fix a broad one"]}, {"heading": "Creative Testing Cadence Matters More Than Creative Quality", "paragraphs": ["A surprising number of Nigerian app marketers treat creative as a one-time production task: shoot a video, run it for a month, replace it when it fatigues. This approach almost always leads to rising CPI over time, because platform algorithms reward fresh creative with better delivery, and Nigerian audiences in particular respond well to creative that feels current and locally relevant.", "We typically test five to ten creative variants per month for an active install campaign, even when an existing ad is performing well. The goal is not to find one perfect ad — it is to maintain a rotation so the algorithm always has fresh signal to optimise against, which keeps delivery costs from climbing as a single creative ages out."]}, {"heading": "What a Realistic CPI Range Looks Like in Nigeria Right Now", "paragraphs": ["Pricing varies significantly by category, but as a general benchmark, fintech and e-commerce apps running well-optimised campaigns in Nigeria are typically seeing blended CPI in the ₦800–₦2,000 range depending on platform and targeting precision, with Google UAC often coming in lower than Meta for high-intent categories, and TikTok performing well for younger consumer audiences when creative is built natively for the platform.", "If your current CPI sits meaningfully above that range, the issue is rarely \"Nigerian advertising is just expensive\" — it is almost always a targeting, creative, or tracking setup problem that can be diagnosed and fixed."]}]'::jsonb, '[{"question": "What is a good cost per install (CPI) for a Nigerian app in 2026?", "answer": "It varies by category, but well-optimised fintech and e-commerce campaigns typically see blended CPI between ₦800 and ₦2,000. Anything significantly higher usually points to a targeting or creative issue worth auditing."}, {"question": "Does TikTok or Meta give cheaper installs in Nigeria?", "answer": "It depends on your audience. TikTok often delivers lower CPI for younger, consumer-facing apps when creative is built natively for the platform. Meta tends to perform more consistently for broader or older demographics and for retargeting."}, {"question": "How often should I refresh ad creative to keep CPI down?", "answer": "We recommend testing 5–10 new creative variants per month for active campaigns, even when existing ads are performing well, since fresh creative helps maintain algorithmic delivery efficiency."}, {"question": "Why has my CPI gone up even though I haven’t changed my campaigns?", "answer": "Rising competition for the same audience pool, naira depreciation against USD-denominated ad pricing, and natural creative fatigue are the three most common causes, even when your own setup hasn’t changed."}]'::jsonb, true)
