insert into blog_posts (slug, title, meta_title, meta_description, category, related_service, excerpt, quick_answer, hero_image, read_minutes, keywords, content, faqs, published)
values ('press-release-writing-guide-nigeria', 'How to Write a Press Release That Nigerian Journalists Actually Read', 'How to Write a Press Release Nigerian Journalists Read | Topton Media', 'A practical guide to writing press releases that get past the inbox and into actual coverage, with specific structure and framing that works for the Nigerian media landscape.', 'PR & Communications', 'pr-communications', 'Most press releases are written from the company’s perspective rather than the reader’s. Here is the structure that actually gets journalists to engage.', 'A press release Nigerian journalists actually read front-loads the actual news in the first paragraph (not company background), uses a specific headline, and includes substantive, non-generic quotes.', 'https://images.unsplash.com/photo-1504711434969-e33886168f5c?w=1400&q=80', 6, ARRAY['press release writing Nigeria', 'how to write press release', 'press release structure', 'Nigerian media outreach', 'press release tips'], '[{"heading": "Write the Headline for a Reader, Not for Your Marketing Team", "paragraphs": ["A press release headline that reads like an internal marketing slogan (\"Company X Revolutionises Industry With Groundbreaking Solution\") tends to get skipped by busy journalists scanning dozens of pitches. A headline framed around the actual news value — what changed, what it means, who it affects — gives a journalist an immediate sense of whether the story fits their beat, which is the first and most important filter a release needs to pass."]}, {"heading": "Front-Load the Actual News, Not the Company Background", "paragraphs": ["Many press releases bury the actual news several paragraphs in, after extensive company background and mission statement language that a journalist does not need in order to evaluate whether the story is worth covering. The most important information — what happened, when, and why it matters — should appear in the first paragraph, with supporting context and company background appearing later for readers who want more detail."], "bullets": ["First paragraph: the core news, stated plainly, with the key facts a journalist needs", "Second paragraph: context for why this matters, ideally connected to a broader trend or market reality", "Quotes: specific and substantive, not generic statements that could apply to any company", "Boilerplate company description: keep it brief and place it near the end, not the beginning"]}, {"heading": "Quotes Should Say Something Specific, Not Generic", "paragraphs": ["A quote like \"We are thrilled to bring this innovation to the Nigerian market\" adds little value to a journalist deciding whether to cover a story, since it could be copy-pasted into any company’s release. A quote that states a specific perspective, data point, or genuine opinion about why the news matters gives a journalist something quotable and substantive to actually use in their coverage."]}]'::jsonb, '[{"question": "How long should a press release be?", "answer": "Most effective releases run 300-500 words. Longer releases risk burying the actual news; the goal is giving a journalist everything needed to evaluate and write the story quickly, not an exhaustive document."}, {"question": "Should I include a quote from my CEO in every press release?", "answer": "Only if the quote says something specific and substantive. A generic quote that could apply to any company adds little value and is often the first thing a journalist skips over."}, {"question": "What is the most common mistake in press releases from Nigerian companies?", "answer": "Burying the actual newsworthy information several paragraphs in, after extensive company background that a journalist does not need to evaluate whether the story is worth covering."}]'::jsonb, true)
